// ===== AUDIO ENGINE (Web Audio API) =====
const AudioCtx = window.AudioContext || window.webkitAudioContext;
let actx = null, musicGain = null, sfxGain = null;
let musicPlaying = false, musicNodes = {};

function initAudio() {
  if (actx) return;
  actx = new AudioCtx();
  musicGain = actx.createGain(); musicGain.gain.value = 0.22;
  sfxGain   = actx.createGain(); sfxGain.gain.value   = 0.55;
  musicGain.connect(actx.destination);
  sfxGain.connect(actx.destination);
  startMusic();
}

/* --- PROCEDURAL MUSIC (synth chiptune loop) --- */
function startMusic() {
  if (musicPlaying) return;
  musicPlaying = true;

  const bpm = 138, beat = 60 / bpm;

  // Bass drone
  function playBass(freq, when, dur) {
    const osc = actx.createOscillator();
    const env = actx.createGain();
    osc.type = 'sawtooth'; osc.frequency.value = freq;
    const filt = actx.createBiquadFilter(); filt.type='lowpass'; filt.frequency.value=300;
    osc.connect(filt); filt.connect(env); env.connect(musicGain);
    env.gain.setValueAtTime(0, when);
    env.gain.linearRampToValueAtTime(0.35, when+0.02);
    env.gain.linearRampToValueAtTime(0, when+dur-0.02);
    osc.start(when); osc.stop(when+dur);
  }

  // Lead arp
  function playArp(freq, when, dur) {
    const osc = actx.createOscillator();
    const env = actx.createGain();
    osc.type = 'square'; osc.frequency.value = freq;
    osc.connect(env); env.connect(musicGain);
    env.gain.setValueAtTime(0.18, when);
    env.gain.exponentialRampToValueAtTime(0.001, when+dur);
    osc.start(when); osc.stop(when+dur);
  }

  // Hi-hat
  function playHat(when) {
    const buf = actx.createBuffer(1, actx.sampleRate * 0.04, actx.sampleRate);
    const d = buf.getChannelData(0);
    for (let i=0;i<d.length;i++) d[i] = (Math.random()*2-1);
    const src = actx.createBufferSource();
    const filt = actx.createBiquadFilter();
    filt.type='highpass'; filt.frequency.value=7000;
    const env = actx.createGain();
    src.buffer=buf; src.connect(filt); filt.connect(env); env.connect(musicGain);
    env.gain.setValueAtTime(0.12,when);
    env.gain.exponentialRampToValueAtTime(0.001,when+0.04);
    src.start(when);
  }

  // Kick
  function playKick(when) {
    const osc = actx.createOscillator(); const env=actx.createGain();
    osc.type='sine'; osc.frequency.setValueAtTime(180,when);
    osc.frequency.exponentialRampToValueAtTime(40,when+0.12);
    osc.connect(env); env.connect(musicGain);
    env.gain.setValueAtTime(0.6,when);
    env.gain.exponentialRampToValueAtTime(0.001,when+0.18);
    osc.start(when); osc.stop(when+0.2);
  }

  // Snare
  function playSnare(when) {
    const buf=actx.createBuffer(1,actx.sampleRate*.12,actx.sampleRate);
    const d=buf.getChannelData(0); for(let i=0;i<d.length;i++) d[i]=(Math.random()*2-1);
    const src=actx.createBufferSource(); const env=actx.createGain();
    src.buffer=buf; src.connect(env); env.connect(musicGain);
    env.gain.setValueAtTime(0.28,when);
    env.gain.exponentialRampToValueAtTime(0.001,when+0.12);
    src.start(when);
  }

  const bassNotes  = [55,55,49,55, 55,52,55,52];
  const arpNotes   = [330,440,550,660,550,440,330,220, 370,494,622,740,622,494,370,247];
  const loopLen    = beat * 16;

  function scheduleLoop(startTime) {
    for(let i=0;i<8;i++){
      playBass(bassNotes[i], startTime+i*beat*2, beat*1.8);
    }
    for(let i=0;i<16;i++){
      playArp(arpNotes[i], startTime+i*beat, beat*.45);
      playHat(startTime+i*beat);
      if(i%4===0) playKick(startTime+i*beat);
      if(i%4===2) playSnare(startTime+i*beat);
    }
  }

  let loopStart = actx.currentTime + 0.05;
  scheduleLoop(loopStart);

  function loop() {
    if(!musicPlaying) return;
    loopStart += loopLen;
    scheduleLoop(loopStart);
    musicNodes.loopTimer = setTimeout(loop, (loopLen - 0.5) * 1000);
  }
  musicNodes.loopTimer = setTimeout(loop, (loopLen - 0.5) * 1000);
}

function stopMusic() {
  musicPlaying = false;
  clearTimeout(musicNodes.loopTimer);
}

/* --- SFX --- */
function sfxHit() {
  if(!actx) return;
  // Sparkle sweep up
  [0,100,220].forEach((delay,i)=>{
    const osc=actx.createOscillator(); const env=actx.createGain();
    osc.type='sine'; osc.frequency.setValueAtTime(440+i*180, actx.currentTime+delay/1000);
    osc.frequency.exponentialRampToValueAtTime(880+i*200, actx.currentTime+delay/1000+0.12);
    osc.connect(env); env.connect(sfxGain);
    env.gain.setValueAtTime(0.3,actx.currentTime+delay/1000);
    env.gain.exponentialRampToValueAtTime(0.001,actx.currentTime+delay/1000+0.18);
    osc.start(actx.currentTime+delay/1000); osc.stop(actx.currentTime+delay/1000+0.2);
  });
}

function sfxCombo(level) {
  if(!actx) return;
  const freqs=[550,660,880,1100,1320];
  const f=freqs[Math.min(level-1,freqs.length-1)];
  const osc=actx.createOscillator(); const env=actx.createGain();
  osc.type='triangle'; osc.frequency.setValueAtTime(f,actx.currentTime);
  osc.frequency.exponentialRampToValueAtTime(f*1.5,actx.currentTime+0.2);
  osc.connect(env); env.connect(sfxGain);
  env.gain.setValueAtTime(0.4,actx.currentTime);
  env.gain.exponentialRampToValueAtTime(0.001,actx.currentTime+0.25);
  osc.start(actx.currentTime); osc.stop(actx.currentTime+0.28);
}

function sfxMiss() {
  if(!actx) return;
  const osc=actx.createOscillator(); const env=actx.createGain();
  osc.type='sawtooth'; osc.frequency.setValueAtTime(200,actx.currentTime);
  osc.frequency.exponentialRampToValueAtTime(80,actx.currentTime+0.15);
  osc.connect(env); env.connect(sfxGain);
  env.gain.setValueAtTime(0.3,actx.currentTime);
  env.gain.exponentialRampToValueAtTime(0.001,actx.currentTime+0.18);
  osc.start(actx.currentTime); osc.stop(actx.currentTime+0.2);
}

function sfxBomb() {
  if(!actx) return;
  const buf=actx.createBuffer(1,actx.sampleRate*.4,actx.sampleRate);
  const d=buf.getChannelData(0); for(let i=0;i<d.length;i++) d[i]=(Math.random()*2-1)*(1-i/d.length);
  const src=actx.createBufferSource(); const filt=actx.createBiquadFilter();
  filt.type='lowpass'; filt.frequency.value=600;
  const env=actx.createGain();
  src.buffer=buf; src.connect(filt); filt.connect(env); env.connect(sfxGain);
  env.gain.setValueAtTime(0.7,actx.currentTime);
  env.gain.exponentialRampToValueAtTime(0.001,actx.currentTime+0.4);
  src.start(actx.currentTime);
}

function sfxFrenzy() {
  if(!actx) return;
  [220,330,440,550,660,880].forEach((f,i)=>{
    setTimeout(()=>{
      const osc=actx.createOscillator(); const env=actx.createGain();
      osc.type='triangle'; osc.frequency.value=f;
      osc.connect(env); env.connect(sfxGain);
      env.gain.setValueAtTime(0.35,actx.currentTime);
      env.gain.exponentialRampToValueAtTime(0.001,actx.currentTime+0.3);
      osc.start(actx.currentTime); osc.stop(actx.currentTime+0.35);
    }, i*70);
  });
}

function sfxGameover() {
  if(!actx) return;
  [440,330,220,110].forEach((f,i)=>{
    setTimeout(()=>{
      const osc=actx.createOscillator(); const env=actx.createGain();
      osc.type='sawtooth'; osc.frequency.value=f;
      osc.connect(env); env.connect(sfxGain);
      env.gain.setValueAtTime(0.3,actx.currentTime);
      env.gain.exponentialRampToValueAtTime(0.001,actx.currentTime+0.4);
      osc.start(actx.currentTime); osc.stop(actx.currentTime+0.45);
    }, i*120);
  });
}

// ===== GAME STATE =====
let score=0, combo=1, maxCombo=1, hits=0, totalClicks=0, bestScore=0;
let timeLeft=30, timerInt=null;
let gameActive=false;
let currentDiff='easy', cfg=DIFF.easy;
let gemId=null, moleId=null, bombId=null;
let gemTimer=null, moleTimer=null, bombTimer=null;
let power=0, powerMode=false, powerModeTimer=null;
let musicEnabled = true;

// ===== DOM REFS =====
const $ = id => document.getElementById(id);

function setImages() {
  ['logo-start','logo-go','logo-main'].forEach(id => {
    const el = $(id); if(el) el.src = LOGO_SRC;
  });
}

// ===== BG CANVAS =====
const bgCanvas = $('bg-canvas');
const bgCtx    = bgCanvas.getContext('2d');
let stars=[], nebulas=[];

function resizeBg() {
  bgCanvas.width  = window.innerWidth;
  bgCanvas.height = window.innerHeight;
}

function initBg() {
  resizeBg(); stars=[];
  const cols=['#a855f7','#6366f1','#06b6d4','#fff','#ec4899','#f59e0b','#818cf8'];
  for(let i=0;i<220;i++){
    stars.push({
      x: Math.random()*bgCanvas.width,
      y: Math.random()*bgCanvas.height,
      r: Math.random()*1.7+.25,
      sp: Math.random()*.5+.18,
      phase: Math.random()*Math.PI*2,
      col: cols[Math.floor(Math.random()*cols.length)]
    });
  }
  nebulas=[
    {x:.22,y:.25,r:.45,c:'rgba(168,85,247,.09)'},
    {x:.78,y:.75,r:.40,c:'rgba(99,102,241,.08)'},
    {x:.50,y:.50,r:.58,c:'rgba(6,182,212,.05)'},
    {x:.08,y:.82,r:.32,c:'rgba(236,72,153,.06)'},
    {x:.90,y:.15,r:.28,c:'rgba(245,158,11,.04)'},
  ];
}

function drawBg(t) {
  const W=bgCanvas.width, H=bgCanvas.height;
  bgCtx.clearRect(0,0,W,H);
  const grd=bgCtx.createLinearGradient(0,0,0,H);
  grd.addColorStop(0,'#03030d'); grd.addColorStop(1,'#06061a');
  bgCtx.fillStyle=grd; bgCtx.fillRect(0,0,W,H);
  nebulas.forEach(n=>{
    const g=bgCtx.createRadialGradient(n.x*W,n.y*H,0,n.x*W,n.y*H,n.r*Math.max(W,H));
    g.addColorStop(0,n.c); g.addColorStop(1,'transparent');
    bgCtx.fillStyle=g; bgCtx.fillRect(0,0,W,H);
  });
  stars.forEach(s=>{
    const f=.5+.5*Math.sin(t*.001*s.sp+s.phase);
    bgCtx.globalAlpha=f*.85+.08;
    bgCtx.fillStyle=s.col;
    bgCtx.beginPath();
    bgCtx.arc(s.x,s.y,s.r*(1+.4*f),0,Math.PI*2);
    bgCtx.fill();
    if(s.r>1.35 && f>.82){
      bgCtx.globalAlpha=(f-.82)*2.5*.35;
      bgCtx.strokeStyle=s.col; bgCtx.lineWidth=.6;
      const len=s.r*5;
      bgCtx.beginPath();
      bgCtx.moveTo(s.x-len,s.y); bgCtx.lineTo(s.x+len,s.y);
      bgCtx.moveTo(s.x,s.y-len); bgCtx.lineTo(s.x,s.y+len);
      bgCtx.stroke();
    }
  });
  bgCtx.globalAlpha=1;
}

// ===== PARTICLE CANVAS =====
const pCanvas=$('particle-canvas');
const pCtx=pCanvas.getContext('2d');
let particles=[];

function resizeP(){ pCanvas.width=window.innerWidth; pCanvas.height=window.innerHeight; }

function spawnGemBurst(x,y,comboLvl){
  const cols=['#a855f7','#c084fc','#f59e0b','#06b6d4','#ec4899','#fbbf24','#e879f9','white'];
  const N=22+comboLvl*6;
  for(let i=0;i<N;i++){
    const a=Math.random()*Math.PI*2, sp=3+Math.random()*8*Math.min(comboLvl,5);
    particles.push({
      type:'circle', x, y,
      vx:Math.cos(a)*sp, vy:Math.sin(a)*sp-3,
      life:1, decay:.016+Math.random()*.026,
      r:3+Math.random()*6,
      col:cols[Math.floor(Math.random()*cols.length)],
      glow:true
    });
  }
  for(let i=0;i<12+comboLvl*2;i++){
    const a=Math.random()*Math.PI*2, sp=2+Math.random()*5;
    particles.push({
      type:'gem', x, y,
      vx:Math.cos(a)*sp, vy:Math.sin(a)*sp-2,
      life:1, decay:.013+Math.random()*.016,
      r:5+Math.random()*9,
      rot:Math.random()*Math.PI*2, rotSpd:(Math.random()-.5)*.28
    });
  }
  particles.push({ type:'ring', x, y, r:4, maxR:90, life:1, decay:.038, col:'rgba(168,85,247,.7)' });
  if(comboLvl>=3){
    particles.push({ type:'ring', x, y, r:4, maxR:120, life:.8, decay:.03, col:'rgba(245,158,11,.5)' });
  }
}

function spawnMissBurst(x,y){
  for(let i=0;i<14;i++){
    const a=Math.random()*Math.PI*2;
    particles.push({
      type:'circle', x, y,
      vx:Math.cos(a)*(1.5+Math.random()*4.5), vy:Math.sin(a)*(1.5+Math.random()*4.5),
      life:1, decay:.042, r:3+Math.random()*4, col:'#ef4444', glow:false
    });
  }
}

function spawnFrenzyBurst(){
  const cx=window.innerWidth/2, cy=window.innerHeight/2;
  const cols=['#a855f7','#f59e0b','#06b6d4','white','#ec4899'];
  for(let i=0;i<60;i++){
    const a=(i/60)*Math.PI*2+Math.random()*.4, sp=5+Math.random()*12;
    particles.push({
      type:'circle',
      x:cx+Math.cos(a)*20, y:cy+Math.sin(a)*20,
      vx:Math.cos(a)*sp, vy:Math.sin(a)*sp-3,
      life:1, decay:.01, r:4+Math.random()*10,
      col:cols[Math.floor(Math.random()*cols.length)], glow:true
    });
  }
  for(let i=0;i<3;i++){
    particles.push({ type:'ring', x:cx, y:cy, r:5, maxR:180+i*60, life:1, decay:.025-i*.005, col:`rgba(168,85,247,${.6-i*.15})` });
  }
}

function drawGemShard(ctx,x,y,r){
  ctx.beginPath();
  const pts=[[0,-r],[r*.6,-r*.3],[r*.72,r*.35],[0,r],[-r*.72,r*.35],[-r*.6,-r*.3]];
  ctx.moveTo(x+pts[0][0],y+pts[0][1]);
  pts.forEach(p=>ctx.lineTo(x+p[0],y+p[1]));
  ctx.closePath(); ctx.fill(); ctx.stroke();
}

function tickParticles(){
  pCtx.clearRect(0,0,pCanvas.width,pCanvas.height);
  particles=particles.filter(p=>p.life>0);
  particles.forEach(p=>{
    if(p.type!=='ring'){ p.x+=p.vx; p.y+=p.vy; p.vy+=.14; }
    p.life-=p.decay;
    const a=Math.max(0,p.life);
    if(p.type==='circle'){
      if(p.glow){ pCtx.shadowColor=p.col; pCtx.shadowBlur=p.r*2.5; }
      pCtx.globalAlpha=a; pCtx.fillStyle=p.col;
      pCtx.beginPath(); pCtx.arc(p.x,p.y,p.r,0,Math.PI*2); pCtx.fill();
      pCtx.shadowBlur=0;
    } else if(p.type==='gem'){
      p.rot+=p.rotSpd;
      pCtx.save(); pCtx.translate(p.x,p.y); pCtx.rotate(p.rot);
      pCtx.globalAlpha=a;
      pCtx.fillStyle='rgba(168,85,247,.65)';
      pCtx.strokeStyle='rgba(192,132,252,.9)'; pCtx.lineWidth=1.2;
      pCtx.shadowColor='#a855f7'; pCtx.shadowBlur=p.r*1.5;
      drawGemShard(pCtx,0,0,p.r);
      pCtx.restore(); pCtx.shadowBlur=0;
    } else if(p.type==='ring'){
      p.r+=(p.maxR-p.r)*.09;
      pCtx.globalAlpha=a*.65;
      pCtx.strokeStyle=p.col; pCtx.lineWidth=3;
      pCtx.shadowColor=p.col; pCtx.shadowBlur=12;
      pCtx.beginPath(); pCtx.arc(p.x,p.y,p.r,0,Math.PI*2); pCtx.stroke();
      pCtx.shadowBlur=0;
    }
    pCtx.globalAlpha=1;
  });
}

// ===== BOARD =====
function buildBoard(){
  const board=$('board');
  board.innerHTML='';
  for(let i=0;i<9;i++){
    const hole=document.createElement('div');
    hole.className='hole'; hole.id='h'+i;
    hole.innerHTML=`
      <div class="hole-inner">
        <div class="hole-pit"></div>
        <div class="hole-character" id="ch${i}"></div>
      </div>`;
    hole.addEventListener('click',()=>onHole(i));
    hole.addEventListener('touchstart',e=>{ e.preventDefault(); onHole(i); }, {passive:false});
    board.appendChild(hole);
  }
}

// ===== SPAWN LOGIC =====
function randHole(ex=[]){
  let id, n=0;
  do{ id=Math.floor(Math.random()*9); n++; } while(ex.includes(id)&&n<30);
  return id;
}

function showChar(id,type){
  const ch=$('ch'+id);
  ch.className='hole-character'; ch.innerHTML='';
  if(type==='gem'){
    const img=document.createElement('img');
    img.src=LOGO_SRC; img.draggable=false;
    ch.appendChild(img); ch.classList.add('gem-char'); gemId=id;
  } else if(type==='mole'){
    const img=document.createElement('img');
    img.src=MOLE_SRC; img.draggable=false;
    ch.appendChild(img); ch.classList.add('mole-char'); moleId=id;
  } else if(type==='bomb'){
    const d=document.createElement('div');
    d.className='bomb-icon'; d.textContent='💣';
    ch.appendChild(d); ch.classList.add('bomb-char'); bombId=id;
  }
  void ch.offsetWidth; ch.classList.add('show');
}

function hideChar(id){
  const ch=$('ch'+id);
  if(!ch||!ch.classList.contains('show')) return;
  ch.classList.remove('show'); ch.classList.add('hide');
  setTimeout(()=>{ ch.classList.remove('hide'); ch.innerHTML=''; ch.className='hole-character'; },230);
}

function schedGem(){
  clearTimeout(gemTimer); if(!gameActive) return;
  const spd = powerMode ? cfg.gemSpeed*.44 : cfg.gemSpeed;
  if(gemId!==null){ hideChar(gemId); gemId=null; }
  const id=randHole([moleId,bombId].filter(x=>x!==null));
  showChar(id,'gem');
  gemTimer=setTimeout(()=>{
    if(gemId===id){ hideChar(id); gemId=null; dropCombo(); }
    schedGem();
  }, spd+Math.random()*260);
}

function schedMole(){
  clearTimeout(moleTimer); if(!gameActive) return;
  if(moleId!==null){ hideChar(moleId); moleId=null; }
  const id=randHole([gemId,bombId].filter(x=>x!==null));
  showChar(id,'mole');
  moleTimer=setTimeout(()=>{
    if(moleId===id){ hideChar(id); moleId=null; }
    schedMole();
  }, cfg.moleSpeed+Math.random()*320);
}

function schedBomb(){
  clearTimeout(bombTimer); if(!gameActive) return;
  if(Math.random()<cfg.bombChance){
    if(bombId!==null){ hideChar(bombId); bombId=null; }
    const id=randHole([gemId,moleId].filter(x=>x!==null));
    showChar(id,'bomb');
    bombTimer=setTimeout(()=>{
      if(bombId===id){ hideChar(id); bombId=null; }
      schedBomb();
    }, cfg.bombSpeed);
  } else {
    bombTimer=setTimeout(schedBomb, 650+Math.random()*450);
  }
}

// ===== CLICK HANDLER =====
function onHole(id){
  if(!gameActive) return;
  initAudio();
  totalClicks++;
  const hole=$('h'+id);
  const rect=hole.getBoundingClientRect();
  const cx=rect.left+rect.width*.5, cy=rect.top+rect.height*.5;

  if(id===gemId){
    const pts=10*combo; score+=pts; hits++;
    power=Math.min(100,power+13);
    hole.classList.add('whacked'); setTimeout(()=>hole.classList.remove('whacked'),380);
    spawnGemBurst(cx,cy,combo);
    showPop(cx,cy,'+'+pts+' 💎','#f59e0b',22);
    sfxHit();
    hideChar(id); gemId=null; schedGem();
    combo=Math.min(combo+1,5); maxCombo=Math.max(maxCombo,combo);
    sfxCombo(combo);
    updateComboUI(); updateScore(); updatePower(); checkFrenzy();

  } else if(id===moleId){
    score+=5; hits++;
    hole.classList.add('whacked'); setTimeout(()=>hole.classList.remove('whacked'),380);
    spawnGemBurst(cx,cy,1);
    showPop(cx,cy,'+5 🐭','#10b981',16);
    sfxHit();
    hideChar(id); moleId=null; schedMole();
    updateScore();

  } else if(id===bombId){
    hole.classList.add('bombed');
    spawnMissBurst(cx,cy); spawnMissBurst(cx,cy);
    sfxBomb();
    showPop(cx,cy,'💣 BOOM!','#ef4444',22);
    screenShake();
    setTimeout(()=>endGame(true), 380);

  } else {
    spawnMissBurst(cx,cy);
    showPop(cx,cy,'MISS!','#ef4444',14);
    hole.classList.add('missed'); setTimeout(()=>hole.classList.remove('missed'),320);
    sfxMiss();
    dropCombo();
  }
}

// ===== COMBO =====
function dropCombo(){
  if(combo>1){
    combo=1; updateComboUI();
    showPop(window.innerWidth/2,180,'COMBO LOST!','#ef4444',13);
  }
}

function updateComboUI(){
  const el=$('combo-val');
  el.textContent='x'+combo;
  el.classList.remove('bump'); void el.offsetWidth; el.classList.add('bump');
  const labels=['','','🔥 DOUBLE!','💥 TRIPLE!','⚡ ULTRA COMBO!','👑 MAX COMBO!!'];
  const cd=$('combo-display');
  cd.textContent=combo>=2?(labels[combo]||'MAX!'):'';
  if(combo>=2){ cd.classList.remove('shake'); void cd.offsetWidth; cd.classList.add('shake'); }
}

// ===== POWER / FRENZY =====
function updatePower(){
  $('power-fill').style.width=power+'%';
  $('power-pct').textContent=power+'%';
  if(power>=100) $('power-fill').classList.add('maxed');
  else $('power-fill').classList.remove('maxed');
}

function checkFrenzy(){
  if(power>=100 && !powerMode){
    powerMode=true; power=0; updatePower();
    spawnFrenzyBurst(); sfxFrenzy();
    $('frenzy-flash').classList.add('active');
    showPop(window.innerWidth/2,window.innerHeight*.4,'💎 CRYSTAL FRENZY! +10s','#a855f7',20);
    timeLeft=Math.min(timeLeft+10,cfg.timeLimit+15);
    clearTimeout(powerModeTimer);
    powerModeTimer=setTimeout(()=>{
      powerMode=false;
      $('frenzy-flash').classList.remove('active');
    },8500);
  }
}

// ===== SCORE =====
function updateScore(){
  const el=$('score-val');
  el.textContent=score;
  el.classList.remove('bump'); void el.offsetWidth; el.classList.add('bump');
}

// ===== FLOATING SCORE POP =====
function showPop(x,y,text,color,size=18){
  const el=document.createElement('div');
  el.className='score-pop';
  el.style.cssText=`left:${x-40}px;top:${y-20}px;font-size:${size}px;color:${color};`;
  el.textContent=text;
  document.body.appendChild(el);
  setTimeout(()=>el.remove(),1100);
}

// ===== SCREEN SHAKE =====
function screenShake(){
  const b=document.querySelector('.board-perspective');
  b.animate([
    {transform:'translateX(-10px) translateY(4px)'},
    {transform:'translateX(10px) translateY(-4px)'},
    {transform:'translateX(-7px) translateY(3px)'},
    {transform:'translateX(7px) translateY(-3px)'},
    {transform:'translateX(-4px)'},
    {transform:'translateX(0)'},
  ],{duration:380,easing:'ease-out'});
}

// ===== TIMER =====
const CIRC = 219.9;

function startTimer(){
  clearInterval(timerInt);
  const max=cfg.timeLimit;
  const arc=$('arc-fill');
  const num=$('timer-val');
  timerInt=setInterval(()=>{
    if(!gameActive){ clearInterval(timerInt); return; }
    timeLeft--;
    num.textContent=timeLeft;
    arc.style.strokeDashoffset=CIRC*(1-timeLeft/max);
    if(timeLeft<=5){
      arc.style.stroke='#ef4444';
      num.classList.add('danger');
      screenShake();
    }
    if(timeLeft<=0) endGame(false);
  },1000);
}

// ===== START =====
function startGame(){
  cfg=DIFF[currentDiff];
  score=0; combo=1; maxCombo=1; hits=0; totalClicks=0; power=0; powerMode=false;
  timeLeft=cfg.timeLimit; gameActive=true;
  gemId=null; moleId=null; bombId=null;
  clearTimeout(gemTimer); clearTimeout(moleTimer); clearTimeout(bombTimer);
  clearTimeout(powerModeTimer); clearInterval(timerInt);

  $('score-val').textContent='0';
  $('combo-val').textContent='x1';
  $('combo-display').textContent='';
  $('timer-val').textContent=timeLeft;
  $('timer-val').classList.remove('danger');
  $('timer-val').style.color='';
  $('arc-fill').style.strokeDashoffset='0';
  $('arc-fill').style.stroke='url(#arcGrad)';
  $('power-fill').style.width='0%';
  $('power-pct').textContent='0%';
  $('power-fill').classList.remove('maxed');
  $('frenzy-flash').classList.remove('active');
  $('diff-indicator').textContent=cfg.label;

  $('start-screen').classList.add('hidden');
  $('gameover-screen').classList.add('hidden');

  buildBoard();
  initAudio();
  startTimer();
  schedGem();
  schedMole();
  schedBomb();
  spawnFrenzyBurst();
}

// ===== END =====
function endGame(bombed){
  gameActive=false;
  clearInterval(timerInt);
  clearTimeout(gemTimer); clearTimeout(moleTimer); clearTimeout(bombTimer); clearTimeout(powerModeTimer);
  $('frenzy-flash').classList.remove('active');
  [gemId,moleId,bombId].filter(x=>x!==null).forEach(id=>hideChar(id));
  gemId=null; moleId=null; bombId=null;
  sfxGameover();

  bestScore=Math.max(bestScore,score);
  const acc=totalClicks>0?Math.round((hits/totalClicks)*100)+'%':'0%';

  let titleTxt="TIME'S UP!", gradeObj=GRADES.find(g=>score>=g.min)||GRADES[GRADES.length-1];
  if(bombed){ titleTxt='💣 BOOM!'; gradeObj={grade:'💥 Blown Up!',msg:'You hit a bomb! Stay sharp next time.'}; }

  $('go-title').textContent=titleTxt;
  $('go-score').textContent=score;
  $('go-grade').textContent=gradeObj.grade;
  $('go-msg').textContent=gradeObj.msg;
  $('go-best').textContent=bestScore;
  $('go-combo').textContent='x'+maxCombo;
  $('go-hits').textContent=hits;
  $('go-acc').textContent=acc;

  setTimeout(()=>{
    $('gameover-screen').classList.remove('hidden');
    spawnFrenzyBurst();
  }, bombed?280:520);
}

// ===== MUSIC TOGGLE =====
function toggleMusic(){
  initAudio();
  musicEnabled=!musicEnabled;
  if(musicEnabled){
    musicGain.gain.value=0.22;
    $('music-toggle').textContent='🔊';
    startMusic();
  } else {
    musicGain.gain.value=0;
    $('music-toggle').textContent='🔇';
    stopMusic();
  }
}

// ===== DIFFICULTY BUTTONS =====
function setupDiffBtns(){
  document.querySelectorAll('.diff-btn').forEach(btn=>{
    btn.addEventListener('click',()=>{
      document.querySelectorAll('.diff-btn').forEach(b=>b.classList.remove('active'));
      btn.classList.add('active');
      currentDiff=btn.dataset.diff;
    });
  });
}

// ===== BUTTON LISTENERS =====
$('play-btn').addEventListener('click', ()=>{ initAudio(); startGame(); });
$('retry-btn').addEventListener('click', ()=>{ initAudio(); startGame(); });
$('menu-btn').addEventListener('click', ()=>{
  $('gameover-screen').classList.add('hidden');
  $('start-screen').classList.remove('hidden');
});

// Kick audio on first interaction
document.addEventListener('pointerdown', initAudio, {once:true});

// ===== MAIN LOOP =====
function loop(t){
  drawBg(t);
  tickParticles();
  requestAnimationFrame(loop);
}

// ===== INIT =====
window.addEventListener('resize',()=>{ resizeBg(); resizeP(); });
setImages();
setupDiffBtns();
initBg(); resizeP(); buildBoard();
requestAnimationFrame(loop);
